mapper.select:
SELECT * FROM ( SELECT rownum rn, t.* FROM ( SELECT h.hotelNo, (SELECT hotelFileName FROM hotel_image WHERE hotelNo = h.hotelNo AND rownum = 1) AS hotelFileName, h.hotelName, h.mainAddress, h.address, h.hotelPhoneNo, h.hotelRegistDate, h.buffet, h.swim, h.golf, h.pet, h.restaurant, h.fitness, h.parking, h.wifi, h.kitchen, h.smoke, m.memberNickname FROM hotel h LEFT JOIN member m ON h.memberNo = m.memberNo
(h.hotelName LIKE '%' || #{keyword} || '%' OR h.mainAddress LIKE '%' || #{keyword} || '%' OR h.address LIKE '%' || #{keyword} || '%')
ORDER BY h.hotelRegistDate DESC ) t WHERE rownum <= #{pageNum} * #{amount} ) WHERE rn > (#{pageNum} - 1) * #{amount}
